B.a_r=new A.af("A vida n\xe3o examinada n\xe3o vale a pena ser vivida.","S\xf3crates")
B.Z7=new A.af("S\xf3 sei que nada sei.","S\xf3crates")
B.YX=new A.af("Conhece-te a ti mesmo.","S\xf3crates")
B.Yx=new A.af("O segredo da mudan\xe7a \xe9 focar toda a sua energia n\xe3o em lutar contra o velho, mas em construir o novo.","S\xf3crates")
B.YW=new A.af("A educa\xe7\xe3o \xe9 acender uma chama, n\xe3o encher um recipiente vazio.","S\xf3crates")
B.YG=new A.af("Seja a mudan\xe7a que voc\xea deseja ver no mundo interior antes de exigi-la no exterior.","S\xf3crates")
B.YI=new A.af("A necessidade \xe9 a m\xe3e da inven\xe7\xe3o.","Plat\xe3o")
B.Z_=new A.af("Quem aprende e aprende e n\xe3o pratica o que sabe, \xe9 como quem ara e ara e nunca semeia.","Plat\xe3o")
B.ZJ=new A.af("O come\xe7o \xe9 a parte mais importante de qualquer trabalho.","Plat\xe3o")
B.Z9=new A.af("A opini\xe3o \xe9 a mediadora entre o conhecimento e a ignor\xe2ncia.","Plat\xe3o")
B.ZG=new A.af("Somos o que fazemos repetidamente. Excel\xeancia, ent\xe3o, n\xe3o \xe9 um ato, mas um h\xe1bito.","Arist\xf3teles")
B.Zp=new A.af("A raiz da educa\xe7\xe3o \xe9 amarga, mas seus frutos s\xe3o doces.","Arist\xf3teles")
B.Zh=new A.af("A felicidade \xe9 o significado e o prop\xf3sito da vida, o objetivo e o fim da exist\xeancia humana.","Arist\xf3teles")
B.YZ=new A.af("O homem s\xe1bio n\xe3o diz tudo que pensa, mas sempre pensa tudo que diz.","Arist\xf3teles")
B.YV=new A.af("\xc9 durante os momentos mais dif\xedceis que encontramos a verdadeira medida do car\xe1ter.","Arist\xf3teles")
B.Zo=new A.af("A virtude \xe9 o meio-termo entre dois extremos, ambos viciosos.","Arist\xf3teles")
B.a_5=new A.af("Devemos ser donos de nossas pr\xf3prias decis\xf5es, n\xe3o escravos das circunst\xe2ncias.","Arist\xf3teles")
B.YO=new A.af("Voc\xea tem poder sobre sua mente, n\xe3o sobre os eventos externos. Perceba isso e encontrar\xe1 for\xe7a.","Marco Aur\xe9lio")
B.a_c=new A.af("A melhor vingan\xe7a \xe9 n\xe3o ser como seu inimigo.","Marco Aur\xe9lio")
B.ZW=new A.af("Perde seu tempo quem busca a aprova\xe7\xe3o dos outros.","Marco Aur\xe9lio")
B.Yl=new A.af("Quando voc\xea acorda de manh\xe3, pense no precioso privil\xe9gio de estar vivo: respirar, pensar, desfrutar e amar.","Marco Aur\xe9lio")
B.YB=new A.af("A qualidade da sua vida \xe9 determinada pela qualidade dos seus pensamentos.","Marco Aur\xe9lio")
B.ZX=new A.af("Nunca estime algo como lucrativo se te for\xe7ar a quebrar sua palavra ou perder seu autorrespeito.","Marco Aur\xe9lio")
B.Yo=new A.af("N\xe3o desperdice o resto de sua vida em pensamentos sobre outras pessoas.","Marco Aur\xe9lio")
B.Z6=new A.af("O homem que faz tudo o que pode dentro das limita\xe7\xf5es que lhe foram impostas faz o suficiente.","Marco Aur\xe9lio")
B.Zz=new A.af("N\xe3o \xe9 o que acontece com voc\xea, mas como voc\xea reage ao que acontece com voc\xea que importa.","Epicteto")
B.Zm=new A.af("Fa\xe7a todo o poss\xedvel para n\xe3o depender de circunst\xe2ncias externas.","Epicteto")
B.Zr=new A.af("N\xe3o procure que as coisas que acontecem sejam como voc\xea quer. Deseje que as coisas que acontecem sejam como s\xe3o e voc\xea encontrar\xe1 tranquilidade.","Epicteto")
B.Yg=new A.af("Temos dois ouvidos e uma boca para que possamos ouvir duas vezes mais do que falamos.","Epicteto")
B.YN=new A.af("A riqueza consiste n\xe3o em ter grandes posses, mas em ter poucas necessidades.","Epicteto")
B.Zd=new A.af("Primeiro diga a si mesmo o que voc\xea ser\xe1; depois fa\xe7a o que tem a fazer.","Epicteto")
B.a_z=new A.af("N\xe3o \xe9 que tenhamos pouco tempo, mas que desperdi\xe7amos muito.","S\xeaneca")
B.Z8=new A.af("Enquanto adiamos, a vida passa.","S\xeaneca")
B.YS=new A.af("\xc9 uma for\xe7a grande n\xe3o precisar de for\xe7a.","S\xeaneca")
B.Zq=new A.af("Retire-se para dentro de si mesmo tanto quanto puder com aqueles que v\xe3o fazer de voc\xea uma pessoa melhor.","S\xeaneca")
B.Zf=new A.af("A dificuldade que voc\xea supera hoje \xe9 a sabedoria que voc\xea carrega amanh\xe3.","S\xeaneca")
B.ZN=new A.af("Cuide do corpo para que a mente possa habit\xe1-lo com prazer.","S\xeaneca")
B.YU=new A.af("Comece. N\xe3o h\xe1 nada que tanto retarde o progresso quanto esperar por ele.","S\xeaneca")
B.Z0=new A.af("Viva com os seres humanos como se Deus te visse; fale com Deus como se os seres humanos te ouvissem.","S\xeaneca")
B.Z5=new A.af("A mudan\xe7a \xe9 a \xfanica constante da vida.","Her\xe1clito")
B.ZL=new A.af("N\xe3o \xe9 poss\xedvel pisar duas vezes no mesmo rio.","Her\xe1clito")
B.ZV=new A.af("O car\xe1ter \xe9 o destino.","Her\xe1clito")
B.ZH=new A.af("Muito aprender n\xe3o ensina a ter bom senso.","Her\xe1clito")
B.YM=new A.af("A jornada de mil milhas come\xe7a com um \xfanico passo.","Lao Tzu")
B.a_a=new A.af("Aquele que se conhece \xe9 s\xe1bio. Aquele que conquista os outros \xe9 forte. Aquele que conquista a si mesmo \xe9 poderoso.","Lao Tzu")
B.Yn=new A.af("A natureza n\xe3o tem pressa, mas realiza tudo.","Lao Tzu")
B.ZU=new A.af("Quando eu deixo de ser o que sou, torno-me o que poderia ser.","Lao Tzu")
B.ZP=new A.af("Seja cuidadoso com seus pensamentos, eles se tornam suas palavras. Seja cuidadoso com suas palavras, elas se tornam suas a\xe7\xf5es.","Lao Tzu")
B.YA=new A.af("Agir sem expectativa, realizar sem fazer alarde \u2014 isso \xe9 a virtude suprema.","Lao Tzu")
B.Yr=new A.af("N\xe3o importa qu\xe3o devagar voc\xea v\xe1, desde que n\xe3o pare.","Conf\xfacio")
B.Yf=new A.af("Fazer o bem por obriga\xe7\xe3o \xe9 virtude; fazer o bem por amor \xe9 sabedoria.","Conf\xfacio")
B.Yz=new A.af("A pessoa que move uma montanha come\xe7a carregando pequenas pedras.","Conf\xfacio")
B.ZC=new A.af("Escolha um trabalho que voc\xea ame e n\xe3o ter\xe1 que trabalhar um \xfanico dia em sua vida.","Conf\xfacio")
B.a_9=new A.af("Antes de se aventurar a melhorar o mundo, d\xea tr\xeas voltas em torno de sua pr\xf3pria casa.","Conf\xfacio")
B.ZO=new A.af("Aquele que aprende mas n\xe3o pensa est\xe1 perdido. Aquele que pensa mas n\xe3o aprende est\xe1 em grande perigo.","Conf\xfacio")
B.ZE=new A.af("O que voc\xea pensa, voc\xea se torna. O que voc\xea sente, voc\xea atrai. O que voc\xea imagina, voc\xea cria.","Buda")
B.Yv=new A.af("A mente \xe9 tudo. O que voc\xea pensa, voc\xea se torna.","Buda")
B.a_w=new A.af("Tr\xeas coisas n\xe3o podem ser escondidas por muito tempo: o sol, a lua e a verdade.","Buda")
B.Zn=new A.af("N\xe3o viva no passado, n\xe3o sonhe com o futuro, concentre a mente no momento presente.","Buda")
B.a_C=new A.af("A paz vem de dentro. N\xe3o a procure fora.","Buda")
B.ZI=new A.af("Voc\xea mesmo, mais do que qualquer outra pessoa no universo, merece seu amor e afeto.","Buda")
B.Ym=new A.af("O que n\xe3o me mata, me fortalece.","Friedrich Nietzsche")
B.YD=new A.af("Aquele que tem um porqu\xea para viver suporta quase qualquer como.","Friedrich Nietzsche")
B.a_e=new A.af("A grandeza do homem est\xe1 em ser uma ponte, n\xe3o um fim.","Friedrich Nietzsche")
B.a_7=new A.af("Sem m\xfasica a vida seria um erro.","Friedrich Nietzsche")
